// 获取欢迎信息
const getGreeting = (country, province, city) => {
  const countryGreeting = greetings[country] || greetings.default;
  if (typeof countryGreeting === 'string') return countryGreeting;

  const provinceGreeting = countryGreeting[province] || countryGreeting.default;
  if (typeof provinceGreeting === 'string') return provinceGreeting;

  return provinceGreeting[city] || provinceGreeting.default;
};

// 获取时间问候语
const getTimeGreeting = () => {
  const hour = new Date().getHours();
  if (hour < 11) return "早上好🌤️ ，一日之计在于晨";
  if (hour < 13) return "中午好☀️ ，记得午休喔~";
  if (hour < 17) return "下午好🕞 ，饮茶先啦！";
  if (hour < 19) return "即将下班🚶‍♂️，记得按时吃饭~";
  return "晚上好🌙 ，夜生活嗨起来！";
};

// 显示欢迎信息
const showWelcome = ({ data, ip }) => {
  if (!data) return showErrorMessage();

  const { lng, lat, country, prov, city, district } = data;
  const BLOG_LOCATION = { lng: 113.61333, lat: 34.74827 };
  const dist = getDistance(BLOG_LOCATION.lng, BLOG_LOCATION.lat, lng, lat);
  const ipDisplay = ip.includes(":") ? "<br>好复杂，咱看不懂~(ipv6)" : ip;
  const pos = country === "中国" ? `${prov} ${city} ${district}` : country;
  const posdesc = getGreeting(country, prov, city);
  const timeChange = getTimeGreeting();

  const welcomeInfoElement = document.getElementById("welcome-info");
  welcomeInfoElement.style.display = 'block';
  welcomeInfoElement.style.height = 'auto';    
  welcomeInfoElement.innerHTML = `
    欢迎来自 <b>${pos}</b> 的小友💖<br>
    当前位置距博主约 <b>${dist}</b> 公里！<br>
    你的IP地址：<b class="ip-address">${ipDisplay}</b><br>
    ${timeChange}<br>
    <b>Tips：${posdesc}🍂</b>
  `;
};

// 显示错误信息并处理重试
const showErrorMessage = (message = '抱歉，无法获取信息') => {
  const welcomeInfoElement = document.getElementById("welcome-info");
  welcomeInfoElement.innerHTML = `
    <div class="error-message">
      <div class="error-icon">😕</div>
      <p>${message}</p>
      <p>请<i id="retry-button" class="fa-solid fa-arrows-rotate"></i>重试或检查网络连接</p>
    </div>
  `;
  
  document.getElementById('retry-button').addEventListener('click', fetchIpInfo);
};

// 处理 PJAX 完成事件
const handlePjaxComplete = () => {
  insertAnnouncementComponent();
  if (isHomePage()) fetchIpInfo();
};

// 判断是否是首页
const isHomePage = () => {
  return window.location.pathname === '/' || window.location.pathname === '/index.html';
};

// 初始化
const initialize = () => {
  addStyles();
  insertAnnouncementComponent();
  if (isHomePage()) {
    fetchIpInfo();
  }
  document.addEventListener("pjax:complete", handlePjaxComplete);
};

window.onload = initialize;